    n = int(next(it))
except StopIteration:
    sys.exit()
stack = []
out_lines = []
for _ in range(n):
    op = next(it)
    if op == 'push':
        x = int(next(it))
        stack.append(x)
    elif op == 'pop':
        if stack:
            stack.pop()
    elif op == 'top':
        out_lines.append(str(stack[-1] if stack else ''))
    elif op == 'empty':
        out_lines.append('true' if not stack else 'false')
print('\n'.join(out_lines))

